mapper.update:
/*
    SQL ID : UserPrfilDAO.userPrfilAlimChange
    설 명 : 사용자 알림수신여부 변경
*/
UPDATE TB_LMS_USER
SET EML_ALIM_RCVYN     = #{emlAlimRcvyn}
    , SHRTNT_ALIM_RCVYN  = #{shrtntAlimRcvyn}
    , PUSH_TALK_SMS_FLAG = #{pushTalkSmsFlag}
    , MDFR_ID = #{userId}
    , MOD_DTTM = FN_DTTM()
WHERE USER_ID = #{userId}

mapper.insert:
/*
    SQL ID : UserPrfilDAO.mergeUserCntct
    설 명 : 사용자연락처 수정
*/
MERGE INTO TB_LMS_USER_CNTCT T
USING (
    SELECT
          #{userId} AS USER_ID
        , #{cntctTycd} AS CNTCT_TYCD
    FROM DUAL
) S
   ON (
        T.USER_ID = S.USER_ID
    AND T.CNTCT_TYCD = S.CNTCT_TYCD
   )
WHEN MATCHED THEN
    UPDATE
       SET CNTCT = #{cntct}
         , MDFR_ID = #{mdfrId}
         , MOD_DTTM = FN_DTTM()
WHEN NOT MATCHED THEN
    INSERT (
          USER_CNTCT_ID
        , USER_ID
        , CNTCT_TYCD
        , CNTCT
        , RGTR_ID
        , REG_DTTM
    )
    VALUES (
          #{userCntctId}
        , #{userId}
        , #{cntctTycd}
        , #{cntct}
        , #{rgtrId}
        , FN_DTTM()
    )

