/*
    SQL ID : UserPrfilDAO.isPswdMtch
    설 명 : 패스워드 일치여부
*/
SELECT COUNT(1)
FROM TB_LMS_USER
WHERE USER_ID = #{userId}
    AND USER_ID_ENCPSWD = #{userIdEncpswd}

mapper.insert:
/*
    SQL ID : UserPrfilDAO.insertUserAuthrtByAuthrtSelect
    설 명 : 권한조회하여 사용자권한등록
*/
INSERT INTO TB_LMS_USER_AUTHRT
(
    USER_AUTHRT_ID
    , USER_ID
    , AUTHRT_ID
    , RGTR_ID
    , REG_DTTM
)
SELECT
    #{userAuthrtId}
    , #{userId}
    , AUTHRT.AUTHRT_ID
    , #{rgtrId}
    , FN_DTTM()
FROM TB_LMS_AUTHRT AUTHRT
WHERE AUTHRT.ORG_ID = #{orgId}
    AND AUTHRT.AUTHRT_CD = #{authrtCd}
    AND AUTHRT.AUTHRT_GRPCD = #{authrtGrpcd}
    AND NOT EXISTS (
    SELECT 1
    FROM TB_LMS_USER_AUTHRT UA
    WHERE UA.USER_ID = #{userId}
    AND UA.AUTHRT_ID = AUTHRT.AUTHRT_ID
)

mapper.delete:
/*
    SQL ID : UserPrfilDAO.deleteUserAuthrtByAuthrtIdList
    설 명 : 권한아이디목록으로 사용자권한 삭제
*/
DELETE
FROM TB_LMS_USER_AUTHRT
WHERE USER_ID = #{userId}
    AND AUTHRT_ID IN

    #{authrtId}

